    public void handleAuthenticationMessage(Client client, Object message)
    {
        //
        //     {
        //         "method": "login",
        //         "id": 1,
        //         "api_key": "K-************************",
        //         "sign": "******************************************************************",
        //         "nonce": 1654215729887
        //     }
        //
        Object messageHash = "authenticated";
        client.resolve(message, messageHash);
    }

    public java.util.concurrent.CompletableFuture<Object> authenticate(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object messageHash = "authenticated";
            var typequeryVariable = this.handleMarketTypeAndParams("authenticate", null, parameters);
            var type = ((java.util.List<Object>) typequeryVariable).get(0);
            var query = ((java.util.List<Object>) typequeryVariable).get(1);
            Object url = Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), type);
            Client client = this.client(url);
            Object future = this.safeValue(client.subscriptions, messageHash);
            if (Helpers.isTrue(Helpers.isEqual(future, null)))
            {
                Object time = this.milliseconds();
                this.checkRequiredCredentials();
                Object requestId = this.requestId();
                Object signData = Helpers.add(this.apiKey, String.valueOf(time));
                Object sign = this.hmac(this.encode(signData), this.encode(this.secret), sha512(), "base64");
                Object request = new java.util.HashMap<String, Object>() {{
                    put( "method", "login" );
                    put( "id", requestId );
                    put( "api_key", ExmoCore.this.apiKey );
                    put( "sign", sign );
                    put( "nonce", time );
                }};
                Object message = this.extend(request, query);
                future = (this.watch(url, messageHash, message, messageHash, null)).join();
                Helpers.addElementToObject(client.subscriptions, messageHash, future);
            }
            return future;
        });

    }
